// Determine source: single-product webhook, batch webhook (translate_missing), or scheduled
const siteConfig = $('Site Config').first().json;
const defaultLang = siteConfig.translation?.default_language || siteConfig.n8npress?.target_language || 'tr';
const activeLangs = siteConfig.translation?.active_languages || [];
const targetLangs = activeLangs.filter(l => l !== defaultLang);
const defaultLanguages = targetLangs.length > 0 ? targetLangs : ['en'];

// Try to get webhook data (may not exist if triggered by schedule)
let webhookData = null;
try {
  webhookData = $('Translation Request Webhook').first()?.json;
} catch(e) {
  webhookData = null;
}

const body = webhookData?.body || webhookData || {};
const isSingleProduct = !!body.product_id && body.event !== 'translate_missing';
const isBatchRequest = body.event === 'translate_missing' || !!body.fetch_pending;

if (isSingleProduct) {
  let langs = defaultLanguages;
  if (body.target_languages) {
    langs = Array.isArray(body.target_languages)
      ? body.target_languages
      : body.target_languages.split(',').map(l => l.trim());
  }
  return [{
    json: {
      product_ids: [body.product_id],
      target_languages: langs,
      default_language: defaultLang,
      source: 'webhook'
    }
  }];
}

if (isBatchRequest) {
  let langs = defaultLanguages;
  if (body.target_languages) {
    langs = Array.isArray(body.target_languages)
      ? body.target_languages
      : body.target_languages.split(',').map(l => l.trim());
  }
  return [{
    json: {
      product_ids: [],
      target_languages: langs,
      default_language: defaultLang,
      post_type: body.post_type || 'product',
      limit: body.limit || 10,
      source: 'batch_webhook',
      fetch_pending: true
    }
  }];
}

// Scheduled: use site-config target_languages
return [{
  json: {
    product_ids: [],
    target_languages: defaultLanguages,
    default_language: defaultLang,
    source: 'schedule',
    fetch_pending: true
  }
}];

const sourceData = $('Determine Source').first().json;
const siteConfig = $('Site Config').first().json;
let productIds = sourceData.product_ids || [];

if (sourceData.fetch_pending) {
  const response = $input.first().json;
  const products = response.products || [];
  productIds = products.map(p => p.product_id || p.id).slice(0, sourceData.limit || 10);
}

const targetLanguages = sourceData.target_languages || [];

// Grab site config values once
const siteUrl = siteConfig.site?.url || siteConfig.site?.home_url || '';
const apiToken = siteConfig.n8npress?.api_token || '';
const aiApiKey = siteConfig.n8npress?.ai?.api_key || '';
const aiModel = siteConfig.n8npress?.ai?.model || 'gpt-4o-mini';
const aiMaxTokens = siteConfig.n8npress?.ai?.max_tokens || 3000;
const defaultLang = sourceData.default_language || 'tr';

// Create one item per product-language combination, each carrying full context
const items = [];
for (const productId of productIds) {
  for (const lang of targetLanguages) {
    items.push({
      json: {
        product_id: productId,
        target_language: lang,
        default_language: defaultLang,
        _site_url: siteUrl,
        _api_token: apiToken,
        _ai_api_key: aiApiKey,
        _ai_model: aiModel,
        _ai_max_tokens: aiMaxTokens
      }
    });
  }
}

if (items.length === 0) {
  return [{ json: { skip: true, message: 'No products to translate' } }];
}

return items;

// Build OpenAI request body safely in Code node
// Read context from the current Loop batch item (stored in Build Translation Matrix output)
const loopItem = $('Loop Over Items').first().json;
const product = $input.first().json;

const ctx = {
  _product_id: loopItem.product_id,
  _target_language: loopItem.target_language,
  _default_language: loopItem.default_language || 'tr',
  _site_url: loopItem._site_url,
  _api_token: loopItem._api_token,
  _ai_api_key: loopItem._ai_api_key,
  _ai_model: loopItem._ai_model || 'gpt-4o-mini',
  _ai_max_tokens: loopItem._ai_max_tokens || 3000
};

// WP REST API uses title.rendered, content.rendered, excerpt.rendered
const productName = product.title?.rendered || product.name || '';
const productDesc = product.content?.rendered || product.description || '';
const shortDesc = product.excerpt?.rendered || product.short_description || '';
// Meta fields: WP REST API returns meta object, WC API returns meta_data array
const meta = product.meta || {};
const metaArr = product.meta_data || [];
const metaTitle = meta.rank_math_title || metaArr.find(m => m.key === 'rank_math_title')?.value || productName;
const metaDesc = meta.rank_math_description || metaArr.find(m => m.key === 'rank_math_description')?.value || '';
const focusKw = meta.rank_math_focus_keyword || metaArr.find(m => m.key === 'rank_math_focus_keyword')?.value || '';

const prompt = `You are an expert SEO-aware translator for e-commerce. Translate the following product content from ${ctx._default_language} to ${ctx._target_language}.

IMPORTANT RULES:
- Preserve brand names exactly as-is (do NOT translate brand names)
- Meta title must be under 60 characters
- Meta description must be under 160 characters
- Maintain keyword density appropriate for the target language
- Use natural, native-sounding language
- Preserve HTML structure in description

Product ID: ${ctx._product_id}
Target Language: ${ctx._target_language}
Product Title: ${productName}
Product Description: ${productDesc}
Short Description: ${shortDesc}
Meta Title: ${metaTitle}
Meta Description: ${metaDesc}
Focus Keyword: ${focusKw}

Respond in valid JSON with these keys:
{
  "product_id": ${ctx._product_id},
  "target_language": "${ctx._target_language}",
  "title": "translated title",
  "description": "translated full description (with HTML)",
  "short_description": "translated short description",
  "meta_title": "translated meta title (<60 chars)",
  "meta_description": "translated meta description (<160 chars)",
  "focus_keyword": "translated focus keyword",
  "slug": "seo-friendly-url-slug"
}

Respond ONLY with valid JSON.`;

const body = JSON.stringify({
  model: ctx._ai_model,
  max_tokens: ctx._ai_max_tokens,
  messages: [
    { role: 'user', content: prompt }
  ]
});

return [{
  json: {
    ...ctx,
    _ai_body: body,
    product_name: productName
  }
}];

// Parse OpenAI response and validate
const ctx = $('Enrich Product Data').first().json;
const response = $input.first().json;

const rawContent = response.choices?.[0]?.message?.content || '{}';
let translated;
try {
  translated = JSON.parse(rawContent);
} catch(e) {
  const match = rawContent.match(/```(?:json)?\s*([\s\S]*?)```/) || rawContent.match(/\{[\s\S]*\}/);
  try {
    translated = match ? JSON.parse(match[1] || match[0]) : null;
  } catch(e2) {
    translated = null;
  }
}

if (!translated) {
  return [{
    json: {
      valid: false,
      error: 'JSON parse failed',
      product_id: ctx._product_id,
      target_language: ctx._target_language,
      product_name: ctx.product_name,
      _site_url: ctx._site_url,
      _api_token: ctx._api_token
    }
  }];
}

const errors = [];
if (translated.meta_title && translated.meta_title.length > 65) {
  errors.push('Meta title too long: ' + translated.meta_title.length + ' chars');
}
if (translated.meta_description && translated.meta_description.length > 165) {
  errors.push('Meta description too long: ' + translated.meta_description.length + ' chars');
}

// Build the callback body right here to avoid expression issues
const callbackPayload = {
  product_id: ctx._product_id,
  language: ctx._target_language,
  content: {
    name: translated.title || translated.name || '',
    description: translated.description || '',
    short_description: translated.short_description || '',
    meta_title: translated.meta_title || '',
    meta_description: translated.meta_description || '',
    focus_keyword: translated.focus_keyword || '',
    slug: translated.slug || ''
  },
  status: errors.length === 0 ? 'completed' : 'needs_review',
  errors: errors
};

return [{
  json: {
    product_id: ctx._product_id,
    product_name: ctx.product_name,
    target_language: ctx._target_language,
    _site_url: ctx._site_url,
    _api_token: ctx._api_token,
    _callback_body: JSON.stringify(callbackPayload),
    _callback_url: ctx._site_url + '/wp-json/n8npress/v1/translation/callback',
    valid: errors.length === 0,
    errors
  }
}];

// Just pass through — translation saved successfully
const saved = $input.first().json;
return [{ json: { done: true } }];
